/** @noinline */
function main() {
    app = new Application();
    app.eventPublisher.listeners = eventListenerRegistry.listeners;
    installPublicApi();
    app.start();

    // backward-button
    window.addEventListener('popstate', event => app.history.onPopState(event));

}

function installPublicApi() {
    installXisPublicApi({
        submitForm(formId, action) {
            return app.submitForm(formId, action);
        },

        openPage(url) {
            return app.pageController.displayPageForUrl(url);
        },

        isEventStreamConnected() {
            return !!(app.eventConnector && app.eventConnector.isConnected());
        },

        closeEventStreams() {
            if (app.eventConnector) {
                app.eventConnector.close();
            }
        }
    });
}

function installXisPublicApi(methods) {
    const currentApi = window['XIS'] || {};
    const api = {};
    for (const key in currentApi) {
        api[key] = currentApi[key];
    }
    for (const key in methods) {
        api[key] = methods[key];
    }
    if (typeof XIS !== 'undefined') {
        XIS = api;
    }
    window['XIS'] = Object.freeze ? Object.freeze(api) : api;
}


window['main'] = main;

class HttpConnector {

    /**
     * @param {string} clientId
     */
    constructor(clientId) {
        this.clientId = clientId;
    }

    /**
     * @public
     * @param {string} uri
     * @param {any} payload
     * @return {Promise<any, int>}
     *
     */
    post(uri, payload, headers, uploads) {
        if (!headers) headers = {};
        if (uploads && uploads.length > 0) {
            const formData = new FormData();
            formData.append('xis-request', JSON.stringify(payload || {}));
            for (const upload of uploads) {
                if (!upload || !upload.file || !upload.fieldName) {
                    continue;
                }
                formData.append(upload.fieldName, upload.file);
            }
            return this.doRequest(uri, headers, 'POST', formData);
        }
        var payloadJson = JSON.stringify(payload);
        headers['Content-type'] = 'application/json';
        return this.doRequest(uri, headers, 'POST', payloadJson);
    }

    /**
     * @public
     * @param {string} uri
     * @param {any} headers
     * @return {Promise<any, int>}
     */
    get(uri, headers) {
        return this.doRequest(uri, headers, 'GET', undefined);
    }

    /**
     * @public
     * @param {string} renewToken 
     * @return {Promise<any, int>}
     * @throws {Error} If the request fails or the response does not contain the expected token data.
     */
    sendRenewTokenRequest(renewToken) {
        return this.httpConnector.post('/xis/token/renew', {}, {});
    }



    /**
     * @private
     * @param {string} uri
     * @param {any} headers
     * @param {string} method
     * @param {any} payload
     * @return {Promise<any>}
     */
    doRequest(uri, headers, method, payload) {
        return this.ensureEventConnection().then(() => this.sendRequest(uri, headers, method, payload));
    }

    sendRequest(uri, headers, method, payload) {
        var xmlHttp = new XMLHttpRequest();
        xmlHttp.open(method, uri, true); // true for asynchronous
        xmlHttp.withCredentials = true;
        if (headers == null) {
            headers = {};
        }
        for (var name of Object.keys(headers)) {
            xmlHttp.setRequestHeader(name, headers[name]);
        }
        var promise = new Promise((resolve, reject) => {
            xmlHttp.onreadystatechange = function () {
                if (xmlHttp.status === 0) {
                    // NICHT aufl?sen, auf onerror warten!
                    return;
                }
                // TODO Handle errors and "304 NOT MODIFIED"
                // TODO Add headers to allow 304
                // Readystaet == 4 for 304 ?
                if (xmlHttp.readyState == 4) { // TODO In Java 204 if there is no server-method
                    resolve(xmlHttp);
                }
                // TODO use errorhandler
            }
            xmlHttp.onerror = function (e) {
                reportError('Error during HTTP request to ' + uri, e);
                reject(xmlHttp);
            };

        });

        if (payload) {
            xmlHttp.send(payload);
        }
        else {
            xmlHttp.send();
        }
        return promise;
    }

    ensureEventConnection() {
        if (typeof app === 'undefined' || !app.eventConnector) {
            return Promise.resolve();
        }
        if (app.initializing) {
            return Promise.resolve();
        }
        if (typeof app.eventConnector.ensureConnected === 'function') {
            return app.eventConnector.ensureConnected();
        } else if (typeof app.eventConnector.isConnected === 'function'
                && typeof app.eventConnector.reconnect === 'function'
                && !app.eventConnector.isConnected()) {
            app.eventConnector.reconnect();
        }
        return Promise.resolve();
    }

}

class Includes {

    /**
     *
     * @param {HttpClient} client
     */
    constructor(client) {
        this.includes = {};
        this.client = client;
    }

    loadIncludes(config) {
        var _this = this;
        var promises = [];
        config.includeIds.forEach(key => _this.includes[key] = null);
        config.includeIds.forEach(key => promises.push(_this.loadInclude(key)));
        return Promise.all(promises).then(() => config);
    }

    /**
    * @returns {Promise<Include>}
    */
    loadInclude(key) {
        var _this = this;
        return this.client.loadInclude(key).then(includeHtml => {
            var include = new Include();
            include.key = key;
            include.html = includeHtml;
            _this.includes[key] = include;
        });
    }

    /**
     * @publicIn
     * @param {string} key
     * @returns {Include}
     */
    getInclude(key) {
        var include = this.includes[key];
        if (include === null || include === undefined) {
            throw new Error('no such include: ' + key);
        }
        return include;
    }

    /**
     * @public
     * @param {string} key
     * @returns {boolean}
     */
    hasInclude(key) {
        return this.includes[key] !== null && this.includes[key] !== undefined;
    }
}

class Store {
    /*
        * @param {EventPublisher} eventPublisher
        * @param {Storage} storageArea
        * @param {string} eventKey
        */
    constructor( eventPublisher, storageArea, eventKey) {
        this.eventPublisher = eventPublisher;
        this.storageArea = storageArea;
        this.eventKey = eventKey;
        this.pathMap = {};
        window.addEventListener('storage', (event) => this.onEvent(event));
    }


    getValue(path) {
        if (path === undefined || path.length === 0) {
            throw new Error('Path is undefined or empty');
        }
    
        const pathArray = path.split('.');
        let key = '';
        let currentValue;
        let i = 0;
        for (; i < pathArray.length; i++) {
            const subpath = pathArray[i];
            if (key !== '') {
                key += '.';
            }
            key += subpath;
    
            // Versuche, den Wert f?r den aktuellen Schl?ssel zu lesen
            const storedString = this.readValue(key);
            if (storedString !== undefined && storedString !== null) {
                currentValue = this.toValue(storedString); // JSON mit "value" auspacken
                break;   
            }   
        }
    
        // Navigiere durch das Objekt, falls es verschachtelt ist und der Pfad noch nicht vollst?ndig aufgel?st wurde
        if (currentValue !== undefined && currentValue !== null) {
            for (let j = i + 1; j < pathArray.length; j++) {
                currentValue = currentValue[pathArray[j]];
                if (currentValue === undefined) {
                    return undefined;
                }
            }
            return currentValue;
        }
    
        return undefined;
    }

    saveValue(path, value) {
        throw new Error('saveValue must be implemented in the subclass');
    }

    /**
     * @protected
     * @param {string} path 
     */
    readValue(path) {
        throw new Error('getValue must be implemented in the subclass');
    }

    removeValue(path) {
       throw new Error('removeValue must be implemented in the subclass');
    }

    /**
     * @protected
    * @param {string} path 
    */
    onEvent(event) {
        if (event.storageArea !== this.storageArea) return;
        this.startUpdate(event.key);
    }

    startUpdate(eventPath) {
        const textContentSet = this.pathMap[eventPath];
        if (textContentSet === undefined) {
            return;
        }
        for (const textContent of textContentSet) {
            textContent.doRefresh(); // initiates reloading stored data
        }
    }


    /**
     * Saves a value to the storage area.  We can not refresh the text, content here,
     * because the data from server is not yet stored !
     * 
     * @public
     * @param {{string: any}} values 
     */
    saveData(values) {
        if (!values) {
            return;
        }
        for (var path of Object.keys(values)) {
            const val = values[path];
            if (typeof val === 'function') {
                // Ignore functions
                continue;
            }
            if (val === undefined || val === null) {
                this.removeValue(path);
            } else {
                this.saveValue(path, this.toStoreString(val));
            }
            this.startUpdate(path);
            this.eventPublisher.publish(this.eventKey, {});
        }
       
    }

    /**
     * @private
     * @param {any} value 
     * @returns {string} json
     */
    toStoreString(value) {
        return JSON.stringify({ value: value });
    }


    /**
     * Converts the stored json string to a value.
     * 
     * @private
     * @param {string} storedString (json)
     * @returns {any}
     */
    toValue(storedString) {
        if (storedString === undefined || storedString === null) {
            return undefined;
        }
        var o = JSON.parse(storedString);
        if (o === undefined) {
            return undefined;
        }
        return o.value;
    }



}

/**
 * Factory for creating TagHandlers for DOM tags.
 * (Formerly: Decorator, now Factory pattern)
 */
class HandlerBuilder {

    /**
     * @param {DomAccessor} domAccessor
     * @param {Client} client for actions and model
     * @param {Frontlets} frontlets
     * @param {Includes} includes
     * @param {FrontletContainers} frontletContainers
     * @param {TagHandlers} tagHandlers
     * @param {Initializer} initializer
     */
    constructor(domAccessor, client, frontlets, includes, frontletContainers, tagHandlers, initializer) {
        this.domAccessor = domAccessor;
        this.client = client;
        this.frontlets = frontlets;
        this.includes = includes;
        this.frontletContainers = frontletContainers;
        this.tagHandlers = tagHandlers;
        this.initializer = initializer;
    }

    /**
     * Creates handlers for a node (recursively for child nodes).
     * @param {Node} node 
     * @param {TagHandler} parentHandler 
     */
    create(node, parentHandler) {
        if (!parentHandler) {
            parentHandler = new RootTagHandler(node);
            this.tagHandlers.mapRootHandler(node, parentHandler);
        }
        if ((isElement(node) && !node.getAttribute('ignore')) || isDocumentFragment(node)) {
            this.createElementHandler(node, parentHandler);
        } else {
            this.createTextNodeHandler(node, parentHandler);
        }
        return parentHandler;
    }

    /**
    * Creates a handler for an element and its attributes/children.
    * @private
    * @param {Element} element
    * @param {TagHandler} parentHandler
    */
    createElementHandler(element, parentHandler) {
        let handler;
        if (element.getAttribute
            && (element.getAttribute('xis:binding') || element.getAttribute('xis:error-binding'))
            && (element.getAttribute('xis:error-class') || element.getAttribute('xis:error-style'))) {
            parentHandler.addDescendantHandler(new ErrorStyleHandler(element));
        }
        switch (element.localName) {
            case 'xis:raw': {
                // Insert content as HTML (default) or as text if text="true"
                const isText = element.getAttribute('text') === 'true';
                const rawContent = nodeListToArray(element.childNodes).map(n => {
                    if (n.nodeType === 3) {
                        return n.nodeValue;
                    }
                    if (n.outerHTML !== undefined) {
                        return n.outerHTML;
                    }
                    if (typeof n.asString === 'function') {
                        return n.asString();
                    }
                    return '';
                }).join('');
                if (isText) {
                    // Insert as plain text node
                    const textNode = document.createTextNode(rawContent);
                    const parent = element.parentNode;
                    parent.insertBefore(textNode, element);
                    parent.removeChild(element);
                } else {
                    // Insert as HTML, but keep DOM structure and listeners
                    const parent = element.parentNode;
                    while (element.firstChild) {
                        parent.insertBefore(element.firstChild, element);
                    }
                    parent.removeChild(element);
                }
                return;
            }
            case 'xis:include':
                handler = this.createIncludeHandler(element);
                this.tagHandlers.mapHandler(element, handler);
                parentHandler.addDescendantHandler(handler);
                return; // Include has no child handlers - content gets replaced
            case 'xis:foreach':
                handler = parentHandler.addDescendantHandler(this.createForeachHandler(element));
                this.tagHandlers.mapHandler(element, handler);
                return; // Do not evaluate child nodes here!
            case 'xis:frontlet-container':
            case 'xis:frontlet-container':
                handler = this.createFrontletContainerHandler(element);
                this.tagHandlers.mapHandler(element, handler);
                parentHandler.addDescendantHandler(handler);
                this.validateNoParentStorageBinding(handler);
                this.createChildNodeHandlers(element, handler);
                return;
            case 'xis:parameter':
                handler = new ParameterTagHandler(element, parentHandler);
                parentHandler.addDescendantHandler(handler);
                break;
            case 'xis:global-messages':
                handler = new GlobalMessageTagHandler(element);
                break;
            case 'input':
                if (element.getAttribute('xis:binding')) {
                    handler = this.createInputHandler(element);
                }
                break;
            case 'textarea':
                if (element.getAttribute('xis:binding')) {
                    handler = new InputTagHandler(element);
                }
                break;
            case 'select':
                if (element.getAttribute('xis:binding')) {
                    handler = this.createSelectHandler(element);
                }
                break;
            case 'form':
                if (element.getAttribute('xis:binding')) {
                    handler = this.createFormHandler(element);
                }
                break;
            case 'submit':
                if (element.getAttribute('xis:action')) {
                    handler = this.createSubmitHandler(element);
                }
                break;
            case 'button':
                  if (element.getAttribute('xis:page') || element.getAttribute('xis:frontlet') || element.getAttribute('xis:action') || element.getAttribute('xis:modal')) {
                    handler = this.createButtonHandler(element);
                }
                break;
            case 'a':
                if (element.getAttribute('xis:page') || element.getAttribute('xis:frontlet') || element.getAttribute('xis:action') || element.getAttribute('xis:modal')) {
                    handler = this.createLinkHandler(element);
                }
                break;
            case 'xis:message':
                handler = new MessageTagHandler(element);
                break;
            case 'xis:if':
                handler = new IfTagHandler(element);
                break;
            case 'xis:storage-binding':
                handler = new StorageBindingHandler(element);
                break;
        }
        
        if (!handler && isElement(element) && element.getAttribute('xis:selection-group')) {
            handler = new SelectionGroupHandler(element);
        }
        if (isElement(element)) { 
            this.initializeAttributes(element, handler ? handler : parentHandler); 
        }
        if (isElement(element) && element.getAttribute('xis:drag')) {
            (handler ? handler : parentHandler).addDescendantHandler(new DragHandler(element));
        }
        if (isElement(element) && element.getAttribute('xis:drop')) {
            (handler ? handler : parentHandler).addDescendantHandler(new DropActionHandler(element, this.client, this.frontletContainers));
        }
        if (handler) {
            parentHandler.addDescendantHandler(handler);
            this.tagHandlers.mapHandler(element, handler);
            this.createChildNodeHandlers(element, handler);
        } else {
            this.createChildNodeHandlers(element, parentHandler);
        }
        return handler;
    }

    /**
     * Creates an InputTagHandler.
     * @private
     * @param {Element} element
     */
    createInputHandler(element) {
        switch (element.getAttribute('type')) {
            case 'checkbox':
                return new CheckboxTagHandler(element);
            case 'radio':
                return new RadioTagHandler(element);
            case 'file':
                return new FileInputHandler(element);
            default:
                return new InputTagHandler(element);
        }
    }

    /**
     * Creates a SelectTagHandler.
     * @private
     * @param {Element} element
     */
    createSelectHandler(element) {
        return new SelectTagHandler(element, this.tagHandlers);
    }

    /**
     * Initializes attribute handlers for dynamic attributes.
     * @private
     * @param {Element} element 
     * @param {TagHandler} parentHandler
     */
    initializeAttributes(element, parentHandler) {
        for (let attrName of element.getAttributeNames()) {
            let attrValue = element.getAttribute(attrName);
            if (attrName === 'xis:selection-group') {
                if (parentHandler.type !== 'selection-group-handler' || parentHandler.tag !== element) {
                    parentHandler.addDescendantHandler(new SelectionGroupHandler(element, attrName));
                }
            }
            else if (attrName === 'xis:selection-class') {
                parentHandler.addDescendantHandler(new SelectionClassHandler(element, attrName));
            }
            else if (attrName === 'xis:src' && attrValue.indexOf('${') !== -1) {
                parentHandler.addDescendantHandler(new AttributeHandler(element, attrName, null, 'src'));
            }
            else if (attrValue.indexOf('${') !== -1) {
                parentHandler.addDescendantHandler(new AttributeHandler(element, attrName));
            }
        }
    }

    /**
    * Creates a FormHandler.
    * @private
    * @param {Element} formElement 
    */
    createFormHandler(formElement) {
        return new FormHandler(formElement, this.client);
    }

    /**
     * Creates a TextNodeHandler for dynamic text nodes.
     * @private
     * @param {Element} node
     * @param {TagHandler} parentHandler
     */
    createTextNodeHandler(node, parentHandler) {
        if (node.nodeValue && node.nodeValue.indexOf('${') !== -1) {
            let handler = new TextNodeHandler(node);
            parentHandler.addDescendantHandler(handler);
            return handler;
        }
    }

    /**
    * Creates handlers for all child nodes.
    * @private
    * @param {Element} element
    * @param {TagHandler} parentHandler 
    */
    createChildNodeHandlers(element, parentHandler) {
        for (const child of nodeListToArray(element.childNodes)) {
            this.create(child, parentHandler);
        }
    }

    /**
     * Creates a link handler depending on the attribute.
     * <a xis:page..> or <a xis:frontlet..> or <a xis:action..> or <a xis:modal..>
     * @private
     * @param {Element} element
     * @returns {TagHandler}
     */
    createLinkHandler(element) {
        let handler;
        if (element.getAttribute('xis:page')) {
            handler = new PageLinkHandler(element);
        }
        if (element.getAttribute('xis:modal')) {
            handler = new ModalLinkHandler(element);
        } else if (element.getAttribute('xis:frontlet')) {
            handler = new FrontletLinkHandler(element, this.frontletContainers);
        } else if (element.getAttribute('xis:action')) {
            handler = new ActionLinkHandler(element, this.client, this.frontletContainers);
        }
        return handler;
    }

    /**
     * Creates a ForeachHandler.
     * @private
     * @param {Element} foreach 
     * @returns {TagHandler}
     */
    createForeachHandler(foreach) {
        return new ForeachHandler(foreach, this.tagHandlers);
    }

    /**
     * Creates a FormSubmitterHandler.
     * @private
     * @param {Element} element
     */
    createSubmitHandler(element) {
        return new FormSubmitterHandler(element);
    }

    /**
     * Creates an ActionButtonHandler.
     * @private
     * @param {Element} element
     */
    createButtonHandler(element) {
        if (element.getAttribute('xis:modal')) {
            return new ModalButtonHandler(element);
        }
        if (element.getAttribute('xis:action')) {
            return new ActionButtonHandler(element, this.client, this.frontletContainers);
        }
        if (element.getAttribute('xis:page')) {
            return new PageButtonHandler(element);
        }
        if (element.getAttribute('xis:frontlet')) {
            return new FrontletButtonHandler(element, this.frontletContainers);
        }
    }

    /**
     * Creates an IncludeHandler.
     * @private
     * @param {Element} element
     * @returns {IncludeHandler}
     */
    createIncludeHandler(element) {
        return new IncludeHandler(element, this.includes, this.initializer);
    }

    /**
     * Creates a FrontletContainerHandler.
     * @private
     * @param {Element} container 
     * @returns {TagHandler}
     */
    createFrontletContainerHandler(container) {
        return new FrontletContainerHandler(
            container,
            this.frontlets,
            this.frontletContainers,
            this.tagHandlers
        );
    }

    validateNoParentStorageBinding(handler) {
        let parent = handler.parentHandler;
        while (parent) {
            if (parent instanceof StorageBindingHandler) {
                console.error('Storage binding on parent element is not allowed for frontlet containers.', handler.tag, parent.tag);
                throw new Error('Storage binding on parent element is not allowed for frontlet containers.');
            }
            parent = parent.parentHandler;
        }
    }
}

class SseConnector {

    constructor(clientId) {
        this.clientId = clientId;
        this.eventSource = null;
        this.eventSources = {};
        this.connected = false;
        this.endpointUrl = null;
        this.endpointUrls = [];
        this.url = null;
        this.connectionPromises = {};
        this.reconnectTimers = {};
        this.reconnectDelayMs = 1000;
        this.maxReconnectDelayMs = 30000;
        this.reconnectAttempts = {};
        this.pendingEventTtlMs = 0;
        this.browserNavigationInProgress = false;
    }

    connect(url) {
        return this.connectAll([url]);
    }

    connectAll(urls) {
        const nextEndpointUrls = [...new Set(urls.filter(url => url))];
        for (const endpointUrl of Object.keys(this.eventSources)) {
            if (!nextEndpointUrls.includes(endpointUrl)) {
                this.closeEndpoint(endpointUrl);
            }
        }
        this.endpointUrls = nextEndpointUrls;
        this.endpointUrl = nextEndpointUrls[0] || null;
        for (const endpointUrl of nextEndpointUrls) {
            this.connectEndpointIfNeeded(endpointUrl);
        }
        this.eventSource = this.endpointUrl ? this.eventSources[this.endpointUrl] : null;
        this.connected = Object.keys(this.eventSources).length > 0;
        return Promise.all(nextEndpointUrls.map(endpointUrl => this.connectionPromiseFor(endpointUrl)))
            .then(() => this);
    }

    connectEndpointIfNeeded(endpointUrl) {
        if (this.browserNavigationInProgress) {
            return Promise.resolve(false);
        }
        const eventSource = this.eventSources[endpointUrl];
        if (eventSource && !this.isClosed(eventSource)) {
            return this.connectionPromiseFor(endpointUrl);
        }
        return this.connectEndpoint(endpointUrl);
    }

    connectEndpoint(endpointUrl) {
        if (this.browserNavigationInProgress) {
            return Promise.resolve(false);
        }
        this.closeEndpoint(endpointUrl, false);
        const eventUrl = appendQueryParameters(endpointUrl, { clientId: this.clientId });
        this.url = eventUrl;
        const eventSource = new EventSource(eventUrl, { withCredentials: true });
        this.eventSources[endpointUrl] = eventSource;
        if (endpointUrl === this.endpointUrl) {
            this.eventSource = eventSource;
        }
        const connectionPromise = new Promise(resolve => {
            const timeout = setTimeout(() => {
                if (this.eventSources[endpointUrl] !== eventSource) {
                    resolve(false);
                    return;
                }
                if (this.shouldIgnoreConnectionError(endpointUrl, eventSource)) {
                    resolve(false);
                    return;
                }
                if (this.isOpen(eventSource)) {
                    this.markConnected(endpointUrl, eventUrl);
                    resolve(true);
                    return;
                }
                console.warn('[SSE] connection timeout for ' + eventUrl);
                this.scheduleReconnect(endpointUrl);
                this.requestAuthenticationCheck(endpointUrl);
                resolve(false);
            }, 5000);
            eventSource.onopen = () => {
                clearTimeout(timeout);
                this.markConnected(endpointUrl, eventUrl);
                resolve(true);
            };
            eventSource.onerror = () => {
                if (this.shouldIgnoreConnectionError(endpointUrl, eventSource)) {
                    clearTimeout(timeout);
                    resolve(false);
                    return;
                }
                this.connected = Object.values(this.eventSources).some(source => source.readyState === 1);
                console.warn('[SSE] connection error for ' + eventUrl);
                clearTimeout(timeout);
                this.closeEndpoint(endpointUrl, false);
                this.scheduleReconnect(endpointUrl);
                this.requestAuthenticationCheck(endpointUrl);
                resolve(false);
            };
        }).finally(() => {
            if (this.connectionPromises[endpointUrl] === connectionPromise) {
                delete this.connectionPromises[endpointUrl];
            }
        });
        this.connectionPromises[endpointUrl] = connectionPromise;
        eventSource.onmessage = (event) => {
            this.handleMessage(event.data);
        };
        return this.connectionPromises[endpointUrl];
    }

    markConnected(endpointUrl, eventUrl) {
        this.connected = true;
        this.reconnectAttempts[endpointUrl] = 0;
        console.debug('[SSE] connected to ' + eventUrl);
    }

    ensureConnected() {
        if (this.browserNavigationInProgress || !this.endpointUrls || this.endpointUrls.length === 0) {
            return Promise.resolve();
        }
        const promises = [];
        for (const endpointUrl of this.endpointUrls) {
            const eventSource = this.eventSources[endpointUrl];
            if (!eventSource || this.isClosed(eventSource)) {
                promises.push(this.connectEndpoint(endpointUrl));
            } else if (this.isOpen(eventSource)) {
                promises.push(Promise.resolve(true));
            } else {
                promises.push(this.connectionPromiseFor(endpointUrl));
            }
        }
        return Promise.all(promises);
    }

    connectionPromiseFor(endpointUrl) {
        return this.connectionPromises[endpointUrl] || Promise.resolve(this.isOpen(this.eventSources[endpointUrl]));
    }

    isClosed(eventSource) {
        const closedState = typeof EventSource !== 'undefined' && EventSource.CLOSED !== undefined ? EventSource.CLOSED : 2;
        return eventSource.readyState === closedState;
    }

    isOpen(eventSource) {
        const openState = typeof EventSource !== 'undefined' && EventSource.OPEN !== undefined ? EventSource.OPEN : 1;
        return eventSource && eventSource.readyState === openState;
    }

    reconnect() {
        if (this.endpointUrls.length > 0) {
            this.connectAll(this.endpointUrls);
        }
    }

    scheduleReconnect(endpointUrl) {
        if (this.browserNavigationInProgress || this.appBrowserNavigationInProgress()) {
            return;
        }
        if (this.reconnectTimers[endpointUrl]) {
            return;
        }
        const attempt = this.reconnectAttempts[endpointUrl] || 0;
        const maxDelay = this.pendingEventTtlMs > 0
                ? Math.min(this.maxReconnectDelayMs, this.pendingEventTtlMs)
                : this.maxReconnectDelayMs;
        const delay = attempt === 0 ? 0 : Math.min(this.reconnectDelayMs * Math.pow(2, attempt - 1), maxDelay);
        this.reconnectAttempts[endpointUrl] = attempt + 1;
        this.reconnectTimers[endpointUrl] = setTimeout(() => {
            delete this.reconnectTimers[endpointUrl];
            if (this.endpointUrls.includes(endpointUrl)) {
                this.connectEndpoint(endpointUrl);
            }
        }, delay);
    }

    setPendingEventTtlMs(pendingEventTtlMs) {
        this.pendingEventTtlMs = pendingEventTtlMs || 0;
    }

    requestAuthenticationCheck(endpointUrl) {
        if (this.browserNavigationInProgress || this.appBrowserNavigationInProgress()) {
            return;
        }
        if (typeof app === 'undefined' || typeof app.checkAuthenticationAfterSseError !== 'function') {
            return;
        }
        app.checkAuthenticationAfterSseError(endpointUrl);
    }

    shouldIgnoreConnectionError(endpointUrl, eventSource) {
        return this.browserNavigationInProgress
            || this.appBrowserNavigationInProgress()
            || this.eventSources[endpointUrl] !== eventSource;
    }

    appBrowserNavigationInProgress() {
        return typeof app !== 'undefined'
            && typeof app.isBrowserNavigationInProgress === 'function'
            && app.isBrowserNavigationInProgress();
    }

    close() {
        for (const endpointUrl of Object.keys(this.eventSources)) {
            this.closeEndpoint(endpointUrl);
        }
        this.eventSource = null;
        this.connected = false;
    }

    closeForBrowserNavigation() {
        this.browserNavigationInProgress = true;
        this.close();
    }

    closeEndpoint(endpointUrl, resetAttempts = true) {
        const eventSource = this.eventSources[endpointUrl];
        if (eventSource) {
            eventSource.close();
            delete this.eventSources[endpointUrl];
        }
        delete this.connectionPromises[endpointUrl];
        if (this.reconnectTimers[endpointUrl]) {
            clearTimeout(this.reconnectTimers[endpointUrl]);
            delete this.reconnectTimers[endpointUrl];
        }
        if (resetAttempts) {
            delete this.reconnectAttempts[endpointUrl];
        }
    }

    isConnected() {
        return this.connected && this.eventSource !== null;
    }

    handleMessage(data) {
        const eventKey = typeof data === 'string' ? data.trim() : '';
        if (!eventKey) {
            return;
        }
        console.debug('[SSE] update-event: key=' + eventKey);
        app.pageController.handleUpdateEvents([eventKey])
            .then(pageUpdated => {
                if (!pageUpdated) {
                    app.frontletContainers.handleUpdateEvents([eventKey]);
                }
            })
            .catch(e => reportError('[SSE] error handling update-event key=' + eventKey, e));
    }
}

/**
 * Hierarchical page-data
 */
class Data {

    /**
     *
     * @param {any} values
     * @param {Data} parentData
     */
    constructor(values, parentData = undefined) {
        this.values = values;
        this.parentData = parentData;
        this.validationPath = '';
        this.load = 'INITIAL';
    }
    /**
     * @public
     * @param {Array<string>} path the path of the data value
     * @returns {any}
     */
    getValue(path) {
        if (path == undefined || path.length == 0) {
            throw new Error('Path is undefined or empty (1)');
        } 
       var dataNode = this.values;
        for (var i = 0; i < path.length; i++) {
            var key = path[i];
            if (dataNode[key] != undefined) {  // false failes for 0
                dataNode = dataNode[key];
                
                // Special handling for Store objects (localStorage, sessionStorage, etc.)
                if (dataNode && typeof dataNode.getValue === 'function' && i < path.length - 1) {
                    // Remaining path should be resolved by the Store
                    const remainingPath = path.slice(i + 1).join('.');
                    return dataNode.getValue(remainingPath);
                }
            } else {
                dataNode = undefined;
                break;
            }
        }
        if (dataNode === undefined && this.parentData) {
            return this.parentData.getValue(path)
        }
        return dataNode;
    }

    getValueByPath(pathStr) {
        return this.getValue(this.doSplit(pathStr));
    }

    /**
     * @public
     * @returns {Array<string>}
     */
    getKeys() {
        return Object.keys(this.values);
    }

    setValueByPath(pathStr, value) {
        if (pathStr == undefined || pathStr.length == 0) {
            throw new Error('Path is undefined or empty (2)');
        } 
        this.setValue(this.doSplit(pathStr, '.'), value);
    }
    /**
     * @public
     * @param {array<string>} path
     * @param {any} value
     */
    setValue(path, value) {
        if (path == undefined || path.length == 0) {
            throw new Error('Path is undefined or empty (3)');
        } 
        var parentDataNode = this.values;
        for (var i = 0; i < path.length - 1; i++) {
            var key = path[i];
            var dataNode = parentDataNode[key];
            if (!dataNode) {
                dataNode = {};
                parentDataNode[key] = dataNode;
            }
            parentDataNode = dataNode;
        }
        var key = path[path.length - 1];
        parentDataNode[key] = value;
    }

    /**
     @ @public
     * @param {String[]} keys 
     * @return {any}
     */
    getValues(keys) {
        var result = {};
        for (var key of keys) {
            result[key] = this.values[key];
        }
        return result;
    }

    /**
 * Splits a path like "a[2].b.c[3]" into parts: ["a", "2", "b", "c", "3"]
 * Ultra-fast: No regex
 * @param {string} path 
 * @param {string} separator 
 * @returns {Array<string>}
 */
 doSplit(path, separator = '.') {
    if (path == undefined || path.length == 0) {
        throw new Error('Path is undefined or empty (4)');
    }
    var parts = [];
    var current = '';
    for (var i = 0; i < path.length; i++) {
        var ch = path[i];
        if (ch === separator) {
            if (current.length > 0) {
                parts.push(current);
                current = '';
            }
        } else if (ch === '[') {
            if (current.length > 0) {
                parts.push(current);
                current = '';
            }
            i++;
            var idx = '';
            while (i < path.length && path[i] !== ']') {
                idx += path[i];
                i++;
            }
            if (idx.length > 0) {
                parts.push(idx);
            }
        } else {
            current += ch;
        }
    }
    if (current.length > 0) {
        parts.push(current);
    }
    return parts;
}
}

/**
 * @typedef Path
 * @property {PathElement} pathElement the first one of linked elements
 * @property pageId
 */
class Path {

    /**
     * 
     * @param {PathElement} pathElement 
     */
    constructor(pathElement) {
        this.pathElement = pathElement;
    }

    isStatic() {
        return this.pathElement.next == undefined && this.pathElement.type == 'static';
    }


    /**
     * Evaluates the path-variables as an array
     * of key-values pairs in original order they 
     * are placed in url.
     * 
     * @public
     * @param {string} realPath 
     * @returns {Array<string: string>} pathVariables in case path is matching, otherwise false
     */
    evaluate(realPath) {
        if (this.pathElement) {
            var pathVariables = [];
            if (this.pathElement.evaluate(realPath, pathVariables)) {
                return pathVariables;
            }
        }
        return false;
    }

    /**
     * Creates a path as an array with path-variables
     * represented by an asterisk.
     * 
     * @public
     * @returns {string}
     */
    normalized() {
        if (this.pathElement) {
            return this.pathElement.appendNormalized();
        }
        return '';
    }
}
