/**
 * @class ObjectProperty
 * @description This class represents an object property in the AST.
 */
class ObjectProperty {
    /**
     * @param {string} path
     * @param {string} key
     */
    constructor(path, key) {
        this.type = 'OBJECT_PROPERTY';
        this.path = path;
        this.key = key;
        this.negated = false;
    }

    /**
     * @public
     * @param {Data} data
     * @returns {string}
     */
    evaluate(data) {
        const variable = data.getValueByPath(this.path);
        const rv = variable[this.key.evaluate(data)];
        return this.negated ? !rv : rv;
    }

    /**
     * @public
     * @returns {string}
     */
    toString() {
        return '.' + this.key;
    }
}

/**
 * @class Negation
 * @description This class represents a negation in the AST.
 */
class Negation {
    constructor() {
        this.type = NOT;
        this.expression = undefined;
    }

    /**
     * @public
     * @param {Data} data
     * @returns {string}
     */
    evaluate(data) {
        return !this.expression.evaluate(data);
    }

    /**
     * 
     * @return
     */
    toString() {
        return '!' + this.expression.toString();
    }
}

/**
 * @class TernaryOperator
 * @description This class represents a ternary operator in the AST.
 */
class TernaryOperator {
    constructor(condition, trueExpression, falseExpression) {
        this.type = 'TERNARY';
        this.condition = condition;
        this.trueExpression = trueExpression;
        this.falseExpression = falseExpression;
        this.negated = false;
    }

    /**
     * @public
     * @param {Data} data
     * @returns {string}
     */
    evaluate(data) {
        const conditionValue = this.condition.evaluate(data);
        const rv = conditionValue ? this.trueExpression.evaluate(data) : this.falseExpression.evaluate(data);
        return this.negated ? !rv : rv;
    }

    /**
     * @public
     * @returns {string}
     */
    toString() {
        return this.condition.toString() + ' ? ' + this.trueExpression.toString() + ' : ' + this.falseExpression.toString();
    }
}

/**
 * @class ArrayLiteral
 * @description Represents a literal array in the AST (e.g., [1, 2, 3])
 */
class ArrayLiteral {
    constructor(elements) {
        this.type = 'ARRAY_LITERAL';
        this.elements = elements;
        this.negated = false;
    }

    /**
     * @public
     * @param {Data} data
     * @returns {Array}
     */
    evaluate(data) {
        const array = this.elements.map(element => element.evaluate(data));
        return this.negated ? !array : array;
    }

    /**
     * @public
     * @returns {string}
     */
    toString() {
        return '[' + this.elements.map(e => e.toString()).join(', ') + ']';
    }
}

