class Pages {
    /**
    * @param {HttpClient} client
    */
    constructor(client) {
        this.client = client;
        this.pages = {};
    }

    /**
     *
     * @param {ClientConfig} config
     * @returns {Promise<any>}
     */
    loadPages(config) {
        this.config = config;
        var promises = [];
        var _this = this;
        config.pageIds.forEach(id => _this.pages[id] = new Page(id, config.pageAttributes[id]));
        config.pageIds.forEach(id => promises.push(_this.loadPageHead(id)));
        config.pageIds.forEach(id => promises.push(_this.loadPageBody(id)));
        config.pageIds.forEach(id => promises.push(_this.loadPageBodyAttributes(id)));
        return Promise.all(promises).then(() => config).catch(e => reportError(e));
    }

    /**
     * @public
     * @returns {Page}
     */
    getWelcomePage() {
        return this.getPage(this.config.welcomePageId);
    }

    /**
     * @public
     * @returns {Array<Path>}
     */
    getAllPaths() {
        return Object.values(this.pages).map(page => page.pageAttributes.path);
    }

    /**
     * @public
     * @param {string} normalizedPath a path with path-variables represented by an asterisk
     */
    getPage(normalizedPath) {
        return this.pages[normalizedPath];
    }

    /**
    * @private
    * @param {string} pageId
    * @returns {Promise<string>}
    */
    loadPageHead(pageId) {
        return this.client.loadPageHead(pageId).then(content => {
            var headChildArray = readHeadChildArray(content);
            var templateElement = htmlToElement(content);
            templateElement = normalizeElement(templateElement);
            initializeElement(templateElement);
            var page = this.pages[pageId];
            page.headChildArray = headChildArray;
            page.headTemplate = templateElement;
            page.titleExpression = { evaluate(_) { } };
            for (var child of headChildArray) {
                if (child.localName == 'title') {
                    page.titleElement = child;
                    break;
                }
            }
            return pageId;
        });
    }


    /**
    * @private
    * @param {string} pageId
    * @returns {Promise<string>}
    */
    loadPageBody(pageId) {
        return this.client.loadPageBody(pageId).then(content => {
            var bodyChildArray = readBodyChildArray(content);
            var templateElement = document.createDocumentFragment();
            for (const node of bodyChildArray) {
                templateElement.appendChild(node);
            }
            templateElement = normalizeElement(templateElement);
            initializeElement(templateElement);
            var page = this.pages[pageId];
            page.bodyTemplate = templateElement;
            return pageId;
        });
    }

    /**
     * @private
     * @param {String} pageId
     * @returns
     */
    loadPageBodyAttributes(pageId) {
        var _this = this;
        return this.client.loadPageBodyAttributes(pageId).then(attributes => {
            _this.pages[pageId].bodyAttributes = attributes;
            return pageId;
        });
    }

    /**
     * for testing
     */
    reset() {
        this.pages = {};
    }
}


class ResolvedURL {

    /**
     * 
     * @param {Path} path
     * @param {Array{string: string}} pathVariables 
     * @param {{string: string}} urlParameters
     * @param {Page} page
     * @param {string} normalizedPath e.g. /x/*.html (* for path-variable)
     */
    constructor(path, pathVariables, urlParameters, page, normalizedPath) {
        this.path = path;
        this.pathVariables = pathVariables;
        this.urlParameters = urlParameters;
        this.page = page;
        this.normalizedPath = normalizedPath;
        this.url = this.toURL();
    }

    /**
    * Merges the array of path-variables an non-array object.
    * 
    * @public
    * @returns {{string: string}}
    */
    pathVariablesAsMap() {
        var map = {};
        for (var pathVariable of this.pathVariables) {
            var name = Object.keys(pathVariable)[0];
            var value = Object.values(pathVariable)[0];
            map[name] = value;
        }
        return map;
    }

    /**
     * @public
     * @returns {string}
     */
    toURL() {
        var url = '';
        var pathElement = this.path.pathElement;
        var pathVarIndex = 0;
        while (pathElement) {
            switch (pathElement.type) {
                case 'static': url += pathElement.content; break;
                case 'variable': {
                    var pathVar = this.pathVariables[pathVarIndex++];
                    url += Object.values(pathVar)[0];
                } break;
                default: throw new Error('unknown element-type: ' + pathElement.type);
            }
            pathElement = pathElement.next;
        }
        var urlParamNames = Object.keys(this.urlParameters);
        if (urlParamNames.length > 0) {
            urlParamNames.sort(); // for comparison
            url += '?';
            for (var i = 0; i < urlParamNames.length; i++) {
                var name = urlParamNames[i];
                url += name;
                url += '=';
                url += this.urlParameters[name]; // already encoded !
                if (i < urlParamNames.length - 1) {
                    url += '&';
                }
            }
        }
        return url;
    }

}
class ModalManager {

    constructor(frontlets, initializer, tagHandlers) {
        this.frontlets = frontlets;
        this.initializer = initializer;
        this.tagHandlers = tagHandlers;
        this.current = undefined;
        this.counter = 0;
    }

    open(modal, parameters, parentContainerHandler) {
        const modalId = app.client.config.getFrontletId(modal);
        const modalParameters = mergeObjects(urlParameters(modal), parameters || {});
        if (!this.current) {
            this.current = this.createModal(parentContainerHandler);
        } else {
            this.current.parentContainerHandler = parentContainerHandler;
        }
        this.current.overlay.classList.add('xis-modal-open');
        this.current.overlay.removeAttribute('hidden');
        this.current.containerHandler.modalParameters = modalParameters;
        return this.current.containerHandler.showFrontlet(
            modalId,
            new FrontletState(app.pageController.resolvedURL, {}, modalParameters)
        );
    }

    handleActionResponse(response, parentContainerHandler) {
        if (response.actionProcessing === 'PAGE') {
            this.close();
            return app.pageController.handleActionResponse(response);
        }
        if (response.nextModalId) {
            const parent = this.current ? this.current.parentContainerHandler : parentContainerHandler;
            return this.openFromResponse(response, parent);
        }
        let promise = Promise.resolve();
        if (response.closeModal) {
            const parent = this.current ? this.current.parentContainerHandler : parentContainerHandler;
            this.close();
            updateStores(response);
            if (response.reloadModalParent) {
                promise = this.reloadParent(parent);
            }
        } else {
            if (this.current && response.modalParameters) {
                this.current.containerHandler.modalParameters = mergeObjects(this.current.containerHandler.modalParameters || {}, response.modalParameters);
            }
            updateStores(response);
        }
        return promise;
    }

    reloadParent(parentContainerHandler) {
        if (parentContainerHandler) {
            return parentContainerHandler.refresh(parentContainerHandler.data);
        }
        return app.pageController.handleUpdateEventNow();
    }

    openFromResponse(response, parentContainerHandler) {
        if (!this.current) {
            this.current = this.createModal(parentContainerHandler);
        } else {
            this.current.parentContainerHandler = parentContainerHandler;
        }
        this.current.overlay.classList.add('xis-modal-open');
        this.current.overlay.removeAttribute('hidden');
        this.current.containerHandler.modalParameters = response.modalParameters || {};
        response.nextFrontletId = response.nextModalId;
        return this.current.containerHandler.handleActionResponse(response);
    }

    close() {
        if (!this.current) {
            return;
        }
        if (this.current.overlay.parentNode) {
            this.current.overlay.parentNode.removeChild(this.current.overlay);
        }
        if (this.current.containerHandler && this.current.containerHandler.frontletInstance) {
            this.current.containerHandler.frontletInstance.dispose();
        }
        this.current = undefined;
    }

    createModal(parentContainerHandler) {
        const overlay = document.createElement('div');
        overlay.className = 'xis-modal-backdrop';
        overlay.setAttribute('hidden', 'hidden');

        const shell = document.createElement('div');
        shell.className = 'xis-modal-shell';
        shell.setAttribute('role', 'dialog');
        shell.setAttribute('aria-modal', 'true');

        const closeButton = document.createElement('button');
        closeButton.setAttribute('type', 'button');
        closeButton.className = 'xis-modal-close';
        closeButton.setAttribute('aria-label', 'Close');
        closeButton.innerHTML = '&times;';
        closeButton.addEventListener('click', event => {
            event.preventDefault();
            this.close();
        });

        const container = document.createElement('xis:frontlet-container');
        container.setAttribute('container-id', '__xis-modal-' + (++this.counter));
        container.className = 'xis-modal-content';

        shell.appendChild(closeButton);
        shell.appendChild(container);
        overlay.appendChild(shell);
        document.body.appendChild(overlay);

        this.initializer.initialize(overlay);
        const containerHandler = this.tagHandlers.getHandler(container);
        return {
            overlay: overlay,
            container: container,
            containerHandler: containerHandler,
            parentContainerHandler: parentContainerHandler
        };
    }
}

/**
 * @class Initializer
 * @package classes/init
 * @access public
 * @description Prepares the dom for using the framework's tag handlers.
 */
class Initializer {

    /**
     *
     * @param {DomAccessor} domAccessor
     * @param {Client} client for action and model
     * @param {Frontlets} frontlets
     * @param {Includes} includes
     * @param {FrontletContainers} frontletContainers
     * @param {TagHandlers} tagHandlers
     */
    constructor(domAccessor, client, frontlets, includes, frontletContainers, tagHandlers) {
        this.handlerBuilder = new HandlerBuilder(domAccessor, client, frontlets, includes, frontletContainers, tagHandlers, this);
        this.domAccessor = domAccessor;
    }


    /**
     * 
     * @param {Node} node 
     * @param {TagHandler} parentHandler 
     */
    initialize(node, parentHandler) {
        return this.handlerBuilder.create(node, parentHandler);
    }

    /**
     * 
     * @param {Element} element 
     * @returns 
     */
    normalizeElement(element) {
        if (!isElement(element) && !isDocumentFragment(element)) {
            return element;
        }
        return new DomNormalizer(element, this.domAccessor).normalize();
    }
}

