/**
 * Utility-class to manipulate the document-tree.
 */
class DomAccessor {

/**
 * Surrounds the given element with the given elementToInsert. Is equivalent to
 * inserting elementToInsert as parent of element.

 * @public
 * @param {Element} element
 * @param {Element} elementToInsert
 */
    surroundWith(element, elementToInsert) {
        this.insertParent(element, elementToInsert);
    }

    /**
     * @public
     * @param {Element} element 
     * @param {Element} elementToInsert 
     */
    insertParent(element, elementToInsert) {
        if (element.parentNode) {
            this.replaceElement(element, elementToInsert);
            elementToInsert.appendChild(element);
        } else {
            elementToInsert.appendChild(element);
        }
    }


    insertBefore(parent, siblings, behind) {
        if (parent) {
            if (!behind) {
              for (var sibling of siblings) {
                 parent.appendChild(sibling);
              }
            } else {
                  for (var sibling of siblings) {
                    parent.insertBefore(sibling, behind);
                }
            }
        }
    }

    /**
     * @public
     * @param {Element} element 
     * @param {Element} elementToInsert 
     */
    insertChild(element, elementToInsert) {
        var childArray = nodeListToArray(element.childNodes);
        for (var child of childArray) {
            element.removeChild(child);
            elementToInsert.appendChild(child);
        }
        element.appendChild(elementToInsert);
    }

    /**
     * @public
     * @param {Element} old 
     * @param {Element} replacement 
     */
    replaceElement(old, replacement) {
        var parent = old.parentNode;
        if (parent) {
            var nextSibling = old.nextSibling;
            parent.removeChild(old);
            if (nextSibling) {
                parent.insertBefore(replacement, nextSibling);
            } else {
                parent.appendChild(replacement);
            }
            // TODO move child nodes ?
        }
    }

    /**
     * Removes an element from the DOM and replaces it with its child nodes.
     * Useful for removing wrapper elements like <xis:foreach> that should not 
     * remain in the DOM structure (e.g., in tables where they break layout).
     * 
     * @public
     * @param {Element} element - The element to unwrap/remove
     */
    unwrapElement(element) {
        var parent = element.parentNode;
        if (!parent) {
            return;
        }
        
        var children = nodeListToArray(element.childNodes);
        var nextSibling = element.nextSibling;
        
        // Insert all children before the element
        for (var child of children) {
            if (nextSibling) {
                parent.insertBefore(child, nextSibling);
            } else {
                parent.appendChild(child);
            }
        }
        
        // Remove the element itself
        parent.removeChild(element);
    }
}
class Application {

    constructor() {
        this.initializers = [];
        this.initializationListeners = [];
        this.messageHandler = window.messageHandler ?  window.messageHandler : new MessageHandler();
        this.eventPublisher = new EventPublisher();
        this.sessionStorage = new SessionStore(this.eventPublisher);
        this.localStorage = new LocalStore(this.eventPublisher);
        this.clientState = new ClientStateStore(this.eventPublisher);
        this.clientId = this.clientId();
        this.httpConnector = new HttpConnector(this.clientId);
        this.httpClient = new HttpClient(this.httpConnector, this.clientId);
        this.httpClient.clientId = this.clientId;
        this.messages = {};
        this.eventConnector = this.createEventConnectorIfSupported(this.clientId);
        this.client = this.httpClient;
        this.domAccessor = new DomAccessor();
        this.pages = new Pages(this.httpClient);
        this.urlResolver = new URLResolver(this.pages);
        this.frontletContainers = new FrontletContainers();
        this.frontlets = new Frontlets(this.httpClient);
        this.tagHandlers = new TagHandlers();
        this.elFunctions = new ELFunctions();
        this.includes = new Includes(this.httpClient);
        this.initializer = new Initializer(this.domAccessor, this.httpClient, this.frontlets, this.includes, this.frontletContainers, this.tagHandlers);
        this.modals = new ModalManager(this.frontlets, this.initializer, this.tagHandlers);
        /** Serializes all render operations (page + frontlet refreshes) so they never overlap. */
        this.renderQueue = Promise.resolve();
        this.frontletLoadGeneration = 0;
        this.pageController = new PageController(this.client, this.pages, this.initializer, this.urlResolver, this.tagHandlers);
        this.history = new PageHistory(this.pageController);
        this.globals = new GlobalStore(this.eventPublisher);
        this.authenticationCheckRunning = false;
        this.lastAuthenticationCheckAt = 0;
        this.authenticationCheckIntervalMs = 5000;
        this.initializing = false;
        this.browserNavigationInProgress = false;
        this.installBrowserNavigationListener();
        this.runInitializers();
    }

    /**
     * Runs all initializers that have been registered.
     * @private
     */
    runInitializers() {
        this.initializers.forEach(initializer => {
            initializer.initialize(this);
        });
    }

    installBrowserNavigationListener() {
        if (typeof window === 'undefined' || typeof window.addEventListener !== 'function') {
            return;
        }
        window.addEventListener('pagehide', () => this.prepareForBrowserNavigation());
        window.addEventListener('beforeunload', () => this.prepareForBrowserNavigation());
    }

    prepareForBrowserNavigation() {
        this.browserNavigationInProgress = true;
        if (this.eventConnector && typeof this.eventConnector.closeForBrowserNavigation === 'function') {
            this.eventConnector.closeForBrowserNavigation();
        }
    }

    isBrowserNavigationInProgress() {
        return this.browserNavigationInProgress;
    }


    start() {
        this.eventPublisher.publish(EventType.APP_INSTANCE_CREATED, this);
        this.initializing = true;
        this.connectEventSources(null);
        this.httpClient.loadConfig()
            .then(config => this.connectEventSources(config))
            .then(config => this.pageController.setConfig(config))
            .then(config => this.httpClient.loadMessages().then(() => config))
            .then(config => {
                if (this.eventConnector && typeof this.eventConnector.setPendingEventTtlMs === 'function') {
                    this.eventConnector.setPendingEventTtlMs(config.pendingEventTtlSeconds * 1000);
                }
                return config;
            })
            .then(config => this.frontletContainers.setConfig(config))
            .then(config => this.includes.loadIncludes(config))
            .then(config => this.frontlets.loadFrontlets(config))
            .then(config => this.pages.loadPages(config))
            .then(() => this.pageController.displayPageForUrl(document.location.pathname + document.location.search))
            .then(() => this.setupLinkInterceptor())
            .then(() => {
                this.initializing = false;
                this.eventPublisher.publish(EventType.APP_INITIALIZED, this);
            })
            .catch(e => {
                this.initializing = false;
                handleError(e);
            });
    }

    checkAuthenticationAfterSseError() {
        const now = Date.now();
        if (this.authenticationCheckRunning || now - this.lastAuthenticationCheckAt < this.authenticationCheckIntervalMs) {
            return;
        }
        if (!this.pageController || !this.pageController.resolvedURL) {
            return;
        }
        this.authenticationCheckRunning = true;
        this.lastAuthenticationCheckAt = now;
        this.pageController.refreshCurrentPage()
            .catch(error => handleError(error))
            .finally(() => this.authenticationCheckRunning = false);
    }

    /**
     * Sets up global link interceptor to prevent full page reloads for internal links.
     * Intercepts all <a href> clicks and routes internal links through the PageController.
     * @private
     */
    setupLinkInterceptor() {
        document.addEventListener('click', (event) => {
            // Find the closest anchor element
            const link = event.target.closest('a[href]');
            if (!link) return;

            // Skip if link already has XIS handler (xis:page, xis:frontlet, xis:action)
            if (link.hasAttribute('xis:page') ||
                link.hasAttribute('xis:frontlet') ||
                link.hasAttribute('xis:action') ||
                link.hasAttribute('xis:modal')) {
                return;
            }

            const href = link.getAttribute('href');

            // Only intercept internal links
            if (this.isInternalLink(href)) {
                event.preventDefault();
                this.pageController.displayPageForUrl(href);
            }
        });
    }

    /**
     * Checks if a link is internal (same-origin, not external protocol).
     * @private
     * @param {string} href - The href attribute value
     * @returns {boolean} True if the link is internal
     */
    isInternalLink(href) {
        if (!href) return false;

        // External protocols
        if (href.startsWith('http://') ||
            href.startsWith('https://') ||
            href.startsWith('//') ||
            href.startsWith('mailto:') ||
            href.startsWith('tel:') ||
            href.startsWith('javascript:')) {
            return false;
        }

        // Hash-only links (same page anchor)
        if (href.startsWith('#')) {
            return false;
        }

        // Download links
        if (href.startsWith('data:') || href.startsWith('blob:')) {
            return false;
        }

        return true;
    }

    createEventConnectorIfSupported(clientId) {
        if (typeof EventSource !== 'undefined') {
            return new SseConnector(clientId);
        }
        return null;
    }

    connectEventSources(config) {
        if (this.eventConnector && typeof this.eventConnector.connectAll === 'function') {
            this.eventConnector.connectAll(this.sseEndpointUrls(config))
                .catch(e => reportError('[SSE] error connecting event source', e));
        }
        return config;
    }

    sseEndpointUrls(config) {
        const endpoints = [this.sseEndpointUrl()];
        if (config) {
            this.addSseEndpointUrls(endpoints, config.pageAttributes);
            this.addSseEndpointUrls(endpoints, config.frontletAttributes);
        }
        return [...new Set(endpoints)];
    }

    addSseEndpointUrls(endpoints, attributesById) {
        if (!attributesById) {
            return;
        }
        for (const attributes of Object.values(attributesById)) {
            if (attributes && attributes.host) {
                endpoints.push(this.sseEndpointUrlForHost(attributes.host));
            }
        }
    }

    sseEndpointUrlForHost(host) {
        if (host.endsWith('/')) {
            return host.substring(0, host.length - 1) + "/xis/events";
        }
        return host + "/xis/events";
    }

    sseEndpointUrl() {
        if (window.location && window.location.origin) {
            return window.location.origin + "/xis/events";
        }
        const protocol = window.location.protocol === 'https:' ? 'https://' : 'http://';
        return protocol + window.location.host + "/xis/events";
    }

    clientId() {
        var clientId = localStorage.getItem('xis.clientId');
        if (!clientId) {
            clientId = randomString();
            localStorage.setItem('xis.clientId', clientId);
        }
        return clientId;
    }

    submitForm(id, action) {
        const form = document.getElementById(id);
        if (form) {
            const formHandler = this.tagHandlers.getHandler(form);
            if (formHandler && formHandler.type === 'form-handler') {
                formHandler.submit(action);
            } else {
                console.error('No form handler found for form with id: ' + id);
            }
        } else {
            console.error('No form found with id: ' + id);
        }
    }

}

class MessageHandler {
    /**
     * @param {HTMLElement} [container=document.getElementById('messages')]
     * @param {Object} [options]
     * @param {{info:number|null, warning:number|null, error:number|null}} [options.autoHideDurations]
     *        ms per level; null disables auto-hide for that level.
     */
    constructor(container, options = {}) {
        this.messageTag = container || document.getElementById('system-messages');
        if (!this.messageTag) {
            console.warn('[MessageHandler] No container element found (id="messages"). Rendering is disabled.');
        }

        this.errorMessages = [];
        this.infoMessages = [];
        this.warningMessages = [];

        // Single timer per level
        this._timers = { error: null, warning: null, info: null };

        const defaults = { info: 5000, warning: 8000, error: null };
        this._autoHideDurations = Object.assign({}, defaults, options.autoHideDurations);
    }

    reportServerError(message) {
        this.showToast(message, 'error');
    }

    /**
     * Validation messages: no auto-hide timer here.
     * Accepts: string[], or { field: string[] }.
     */
    addValidationErrors(errors) {
        if (Array.isArray(errors)) {
            errors.forEach(msg => this.addMessage(msg, 'error', { render: false, autoHide: false }));
        } else if (errors && typeof errors === 'object') {
            Object.values(errors).forEach(arr => {
                if (Array.isArray(arr)) {
                    arr.forEach(msg => this.addMessage(msg, 'error', { render: false, autoHide: false }));
                }
            });
        } else if (errors != null) {
            this.addMessage(String(errors), 'error', { render: false, autoHide: false });
        }
        this._render();
    }

    addInfoMessage(message)    { this.addMessage(message, 'info'); }
    addWarningMessage(message) { this.addMessage(message, 'warning'); }
    addErrorMessage(message)   { this.addMessage(message, 'error'); }

    /** Clears all levels and cancels timers. */
    clearMessages() {
        this.errorMessages = [];
        this.infoMessages = [];
        this.warningMessages = [];
        this._clearToastContainer();
        this._cancelTimer('error');
        this._cancelTimer('warning');
        this._cancelTimer('info');
        this._render();
    }

    clearErrors()   { this._clearLevel('error'); }
    clearWarnings() { this._clearLevel('warning'); }
    clearInfos()    { this._clearLevel('info'); }

    /**
     * Adds a message at a given level.
     * 3rd param is backward-compatible:
     *  - boolean => render immediately (autoHide = default by level)
     *  - object  => { render?: boolean, autoHide?: boolean }
     */
    addMessage(message, level, renderOrOptions = true) {
        const { render, autoHide } = this._normalizeAddOptions(level, renderOrOptions);

        const msg = this._coerceMessage(message);
        const bucketKey = `${level}Messages`;
        const messageArray = this[bucketKey];

        if (!Array.isArray(messageArray)) {
            console.warn(`[MessageHandler] Unknown level: ${level}`);
            return;
        }

        if (!messageArray.includes(msg)) {
            messageArray.push(msg);

            // Start per-level timer if configured and not already running.
            if (autoHide) this._ensureTimer(level);

            if (render) this._render();
        }
    }

    showToast(message, level = 'info') {
        const toastContainer = this._toastContainer();
        const normalizedLevel = String(level || 'info').toLowerCase();
        const toast = document.createElement('div');
        toast.classList.add('xis-toast');
        toast.classList.add(normalizedLevel);
        toast.setAttribute('role', normalizedLevel === 'error' ? 'alert' : 'status');
        toast.setAttribute('aria-live', normalizedLevel === 'error' ? 'assertive' : 'polite');
        toast.textContent = message == null ? '' : String(message);
        toastContainer.appendChild(toast);
        setTimeout(() => toast.remove(), 5000);
    }

    /* --------------------------- Internal helpers --------------------------- */

    _toastContainer() {
        let container = document.getElementById('xis-toast-container');
        if (!container) {
            container = document.createElement('div');
            container.id = 'xis-toast-container';
            container.className = 'xis-toast-container';
            document.body.appendChild(container);
        }
        return container;
    }

    _clearToastContainer() {
        const container = document.getElementById('xis-toast-container');
        if (!container) {
            return;
        }
        while (container.firstChild) {
            container.removeChild(container.firstChild);
        }
    }

    _normalizeAddOptions(level, renderOrOptions) {
        if (typeof renderOrOptions === 'boolean') {
            return { render: renderOrOptions, autoHide: this._autoHideDurations[level] != null };
        }
        const render = renderOrOptions?.render !== undefined ? !!renderOrOptions.render : true;
        const autoHide = renderOrOptions?.autoHide !== undefined
            ? !!renderOrOptions.autoHide
            : (this._autoHideDurations[level] != null);
        return { render, autoHide };
    }

    _coerceMessage(input) {
        if (input == null) return '';
        if (typeof input === 'string') return input;
        if (input instanceof Error) return input.message || String(input);
        return String(input);
    }

    _clearLevel(level) {
        this[`${level}Messages`] = [];
        this._cancelTimer(level);
        this._render();
    }

    _ensureTimer(level) {
        const duration = this._autoHideDurations[level];
        if (duration == null) return; // auto-hide disabled for this level
        if (this._timers[level] != null) return; // keep existing timer; do not reset

        this._timers[level] = setTimeout(() => {
            this._timers[level] = null;
            this[`${level}Messages`] = [];
            this._render();
        }, duration);
    }

    _cancelTimer(level) {
        const id = this._timers[level];
        if (id != null) {
            clearTimeout(id);
            this._timers[level] = null;
        }
    }

    _render() {
        if (!this.messageTag) return;

        // Clear container (no innerHTML)
        while (this.messageTag.firstChild) {
            this.messageTag.removeChild(this.messageTag.firstChild);
        }

        // Build and append blocks directly (no DocumentFragment for GraalVM compatibility)
        const errorEl   = this._createLevelBlock('error');
        const warningEl = this._createLevelBlock('warning');
        const infoEl    = this._createLevelBlock('info');

        if (errorEl)   this.messageTag.appendChild(errorEl);
        if (warningEl) this.messageTag.appendChild(warningEl);
        if (infoEl)    this.messageTag.appendChild(infoEl);
    }

    _createLevelBlock(level) {
        const messages = this[`${level}Messages`];
        if (!messages || messages.length === 0) return null;

        let container;
        const isSingle = messages.length === 1;

        if (isSingle) {
            container = document.createElement('div');
            container.className = level;
            container.appendChild(document.createTextNode(messages[0]));
        } else {
            container = document.createElement('ul');
            container.className = level;
            messages.forEach(msg => {
                const li = document.createElement('li');
                li.textContent = msg;
                container.appendChild(li);
            });
        }

        // Accessibility roles without styling implications
        if (level === 'error') {
            container.setAttribute('role', 'alert');
            container.setAttribute('aria-live', 'assertive');
        } else {
            container.setAttribute('role', 'status');
            container.setAttribute('aria-live', 'polite');
        }

        return container;
    }
}

/**
 * A tokenizer for JavaScript-like scripts.
 */
class ScriptTokenizer {

    /**
     * Creates a new tokenizer for the given script.
     * @param {string} script The script to tokenize.
     */
    constructor(script) {
        this.script = script.toString();
        this.tokens = [];
        this.index = 0;
    }

    tokenize() {
        while (this.index < this.script.length) {
            this.skipWhitespace();
            if (this.index >= this.script.length) break;

            const c = this.peekChar();
            if (this.isColon(c)) {
                this.addToken({ type: COLON });
                this.index++;
            } else if (this.isQuestionMark(c)) {
                this.addToken({ type: QUESTION_MARK });
                this.index++;
            } else if (this.isDot(c)) {
                this.addToken({ type: DOT });
                this.index++;
            } else if (this.isOpeningSquareBracket(c)) {
                this.processArrayStart();
            } else if (this.isClosingSquareBracket(c)) {
                this.processArrayEnd();
            } else if (this.isStringStart(c)) {
                this.processString();
            } else if (this.isDigit(c)) {
                this.processNumber();
            } else if (this.isIdentifierStart(c)) {
                this.processIdentifier();
            } else if (this.isTwoCharOperator(c)) {
                this.processTwoCharOperator();
            } else if (this.isSingleCharOperator(c)) {
                this.processSingleCharOperator();
            } else if (c === ',') {
                this.addToken({ type: COMMA });
                this.index++;
            } else {
                throw new Error("Unrecognized character: '" + c + "' in '" + this.script + "' at position " + this.index);
            }
        }
        return this.tokens;
    }

    // Hilfsmethoden

    skipWhitespace() {
        while (this.index < this.script.length && /\s/.test(this.script.charAt(this.index))) {
            this.index++;
        }
    }

    peekChar(offset = 0) {
        return this.script.charAt(this.index + offset);
    }
    
    addToken(token) {
        token.index = this.tokens.length;
        this.tokens.push(token);
        return token;
    }
    

    // Array-Verarbeitung
    isOpeningSquareBracket(c) {
        return c === '[';
    }

    isClosingSquareBracket(c) {
        return c === ']';
    }

    isQuestionMark(c) {
        return c === '?';
    }

    isDot(c) {
        return c === '.';
    }

    processArrayStart() {
        this.addToken({ type: OPENING_SQUARE_BRACKET, index: this.index });
        this.index++; // Skip '['
    }

    processArrayEnd() {
        this.addToken({ type: CLOSING_SQUARE_BRACKET, index: this.index });
        this.index++; // Skip '['
    }

    // String-Verarbeitung
    isStringStart(c) {
        return c === '"' || c === "'";
    }

    processString() {
        const token = this.readString();
        token.type = STRING;
        this.addToken(token);
    }

    readString() {
        const quoteChar = this.peekChar();
        this.index++; // Skip starting quote
        let str = '';
        while (this.index < this.script.length) {
            let c = this.peekChar();
            if (c === '\\') { // Escapesequenz
                str += c;
                this.index++;
                if (this.index < this.script.length) {
                    str += this.peekChar();
                    this.index++;
                }
            } else if (c === quoteChar) {
                this.index++; // Skip closing quote
                break;
            } else {
                str += c;
                this.index++;
            }
        }
        return { value: str };
    }

    // Zahlen-Verarbeitung
    isDigit(c) {
        return /\d/.test(c);
    }

    isColon(c) {
        return c === ':';
    }

    processNumber() {
        const token = this.readNumber();
        token.type = token.isFloat ? FLOAT : INTEGER;
        this.addToken(token);
    }

    readNumber() {
        let numStr = '';
        let isFloat = false;
        while (this.index < this.script.length && /[0-9.]/.test(this.peekChar())) {
            let c = this.peekChar();
            if (c === '.') {
                isFloat = true;
            }
            numStr += c;
            this.index++;
        }
        const value = isFloat ? parseFloat(numStr) : parseInt(numStr, 10);
        return { value, isFloat };
    }

    // Identifiers and literals (for example true, false)
    isIdentifierStart(c) {
        return /[a-zA-Z_]/.test(c);
    }

    processIdentifier() {
        const token = this.readIdentifier();
        if (token.value === "true" || token.value === "false") {
            token.type = BOOL;
            token.value = token.value === "true";
        } else if (token.value === "null" || token.value === "undefined") {
            token.type = NULL_OR_UNDEFINED;
            token.value = null;
        } else {
            token.type = IDENTIFIER;
            token.name = token.value;
        }
        this.addToken(token);
    }

    readIdentifier() {
        let idStr = '';
        while (this.index < this.script.length && /[a-zA-Z0-9_]/.test(this.peekChar())) {
            idStr += this.peekChar();
            this.index++;
        }
        return { value: idStr};
    }

    // Operatoren

    isTwoCharOperator(c) {
        const nxt = this.peekChar(1);
        return (c === '&' && nxt === '&') ||
               (c === '|' && nxt === '|') ||
               (c === '!' && nxt === '=') ||
               (c === '=' && nxt === '=') ||
               (c === '>' && nxt === '=') ||
               (c === '<' && nxt === '=') ||
               (c === '+' && (nxt === '+' || nxt === '=')) ||
               (c === '-' && (nxt === '-' || nxt === '=')) ||
               (c === '*' && nxt === '=') ||
               (c === '/' && nxt === '=') ||
               (c === '%' && nxt === '=');
    }
    
    processTwoCharOperator() {
        const c = this.peekChar();
        const nxt = this.peekChar(1);
        const op = c + nxt;
        let type;
        switch (op) {
            case "&&": type = AND; break;
            case "||": type = OR; break;
            case "!=": type = NOT_EQUAL; break;
            case "==": type = EQUAL; break;
            case ">=": type = GREATER_EQUAL; break;
            case "<=": type = LESS_EQUAL; break;
            case "++": type = INCREMENT; break;
            case "--": type = DECREMENT; break;
            case "+=": type = ADD_ASSIGN; break;
            case "-=": type = SUB_ASSIGN; break;
            case "*=": type = MUL_ASSIGN; break;
            case "/=": type = DIV_ASSIGN; break;
            case "%=": type = MOD_ASSIGN; break;
            default:
                throw new Error("Unknown two-character operator: " + op);
        }
        this.addToken({ type, op });
        this.index += 2;
    }
    
    isSingleCharOperator(c) {
        return ['!', '>', '<', '+', '-', '*', '/', '%', '=', '(', ')'].includes(c);
    }

    processSingleCharOperator() {
        const c = this.peekChar();
        let type;
        switch(c) {
            case '!': type = NOT; break;
            case '>': type = GREATER; break;
            case '<': type = LESS; break;
            case '+': type = ADD; break;
            case '-': type = SUB; break;
            case '*': type = MUL; break;
            case '/': type = DIV; break;
            case '%': type = MOD; break;
            case '=': type = ASSIGN; break;
            case '(': type = OPEN_BRACKET; break;
            case ')': type = CLOSE_BRACKET; break;
            default:
                throw new Error("Unknown operator: " + c);
        }
        this.addToken({ type, op: c });
        this.index++;
    }
}

// Constants for token types
const STRING = 1;
const INTEGER = 2;
const FLOAT = 3;
const BOOL = 4;
const NULL_OR_UNDEFINED = 5;
const AND = 9;
const OR = 10;
const NOT = 11;
const EQUAL = 12;
const NOT_EQUAL = 13;
const GREATER = 14;
const GREATER_EQUAL = 15;
