/**
 * @property {string} clientId
 * @property {string} pageId
 * @property {string} pageUrl
 * @property {string} frontletId 
 * @property {string} frontletContainerId
 * @property {string} action
 * @property {string} formBinding
 * @property {any} formData
 * @property {string: string} pathVariables
 * @property {string: string} urlParameters
 * @property {string: string} queryParameters
 * @property {string: string} actionParameters
 * @property {string: string} frontletParameters
 * @property {string: string} modalParameters
 * @property {string} load
 * @property {string} zoneId
 * @property {string} locale
 * @property {string} accessToken
 * @property {string} renewToken
 * @property {string: string} type;
 * @property {string: string} sessionStorageData
 * @property {string: string} clientStateData
 * @property {string: string} localStorageData
 * @property {string: string} globalVariableData
*/
class ClientRequest {

    constructor() {
        this.clientId = '';
        this.pageId = '';
        this.pageUrl = '';
        this.frontletId = '';
        this.frontletContainerId = '';
        this.action = '';
        this.formBinding = '';
        this.formData = {};
        this.pathVariables = {};
        this.urlParameters = {};
        this.queryParameters = {};
        this.actionParameters = {};
        this.frontletParameters = {};
        this.modalParameters = {};
        this.load = 'INITIAL';
        this.zoneId = '';
        this.locale = '';
        this.accessToken = '';
        this.renewToken = '';
        this.type = '';
        this.sessionStorageData = {};
        this.clientStateData = {};
        this.localStorageData = {};
        this.globalVariableData = {};
    }

    toJSON() {
        const compact = {};
        for (const key of Object.keys(this)) {
            const value = this[key];
            if (this.hasPayload(value)) {
                compact[key] = value;
            }
        }
        return compact;
    }

    hasPayload(value) {
        if (value === undefined || value === null || value === '') {
            return false;
        }
        if (Array.isArray(value)) {
            return value.length > 0;
        }
        if (typeof value === 'object') {
            return Object.keys(value).length > 0;
        }
        return true;
    }
}

/**
 * @class Include
 * @package classes/include
 * @access public
 * @description Represents a single include with its HTML content and root handler
 * 
 * @property {String} key
 * @property {String} html
 * @property {RootTagHandler} rootHandler
 */
class Include {
    constructor() {
        this.key = undefined;
        this.html = undefined;
        this.includeInstances = [];
    }

    fetchIncludeInstance() {
        if (this.includeInstances.length == 0) {
            return new IncludeInstance(this.key, this.html);
        }
        return this.includeInstances.pop();
    }

    releaseIncludeInstance(includeInstance) {
        this.includeInstances.push(includeInstance);
    }
}

/**
 * Util-class to navigate among
 * a string's characters.
 */
class CharIterator {

    /**
     *
     * @param {string} src
     */
    constructor(src) {
        if (!isSet(src)) {
            src = '';
        }
        this.src = src;
        this.index = -1;
    }

    /**
     * @public
     * @returns {boolean}
     */
    hasNext() {
        return this.index + 1 < this.src.length;
    }

    /**
     * @public
     * @returns {any}
     */
    current() {
        return this.src[this.index];
    }

    /**
     * @public
     * @returns {any}
     */
    next() {
        this.index++;
        return this.src[this.index];
    }

    /**
     * @public
     * @returns {any}
     */
    beforeCurrent() {
        return this.index - 1 > -1 ? this.src[this.index - 1] : undefined;
    }

    /**
     * @public
     * @returns {any}
     */
    afterCurrent() {
        return this.index + 1 < this.src.length ? this.src[this.index + 1] : undefined;
    }

}
/**
 * @property {array<string>} pageIds
 * @property {array<string>} frontletIds
 * @property {string: PageAttributes} pageAttributes
 * @property {string: FrontletAttributes} frontletAttributes
 */

class ClientConfig {

    constructor() {
        this.pageIds = [];
        this.frontletIds = [];
        this.welcomePageId = undefined;
        this.pageAttributes = {}
        this.frontletAttributes = {};
        this.pendingEventTtlSeconds = 0;
    }

    /**
     * Returns the remote host for the given page (normalised path), or undefined if local.
     * @public
     * @param {string} normalizedPath
     * @returns {string|undefined}
     */
    getPageHost(normalizedPath) {
        const attrs = this.pageAttributes[normalizedPath];
        return attrs ? attrs.host : undefined;
    }

    /**
     * Returns the remote host for the given frontlet-id, or undefined if local.
     * @public
     * @param {string} frontletId
     * @returns {string|undefined}
     */
    getFrontletHost(frontletId) {
        const attrs = this.frontletAttributes[frontletId];
        return attrs ? attrs.host : undefined;
    }

    /**
     * Resolves a public frontlet URL or a frontlet id to the configured frontlet id.
     * @public
     * @param {string} frontlet
     * @returns {string}
     */
    getFrontletId(frontlet) {
        const frontletWithoutQuery = stripQuery(frontlet);
        for (const id of Object.keys(this.frontletAttributes)) {
            const attrs = this.frontletAttributes[id];
            if (attrs && attrs.url === frontletWithoutQuery) {
                return id;
            }
        }
        return frontletWithoutQuery;
    }
}

class EventPublisher {
    constructor() {
        this.listeners = {};
    }

    addEventListener(eventKey, listener) {
        if (!this.listeners[eventKey]) {
            this.listeners[eventKey] = [];
        }
        this.listeners[eventKey].push(listener);
    }

    removeEventListener(listener) {
       for (const eventKey in this.listeners) {
            const listeners = this.listeners[eventKey];
            const index = listeners.indexOf(listener);
            if (index > -1) {
                listeners.splice(index, 1);
            }
       }
    }

    publish(eventKey, data) {
        if (!this.listeners[eventKey]) return;
        this.listeners[eventKey].forEach(listener => listener(data));
    }
}

class TagHandler {

    /**
     * 
     * @param {Element} tag 
     */
    constructor(tag) {
        this.tag = tag;
        this.descendantHandlers = [];
        this.parentHandler = null;
        this.type = 'tag-handler';
        this.priority = 'normal';
        this.expressionParser = new ExpressionParser(elFunctions);
    }

    addDescendantHandler(handler) {
        handler.parentHandler = this;
        this.descendantHandlers.push(handler);
        handler.publishBindEvent();
        return handler;
    }

    removeDescendantHandler(handler) {
        const handlers =[];
        for (var h of this.descendantHandlers) {
            if (h != handler) {
                handlers.push(h);
            }
        }
        this.descendantHandlers = handlers;
        handler.parentHandler = null;   
    }

    refresh(data) {
        throw new Error('abstract method: refresh must be implemented by subclass');
    }

    /**
     * Refreshes this handler and all descendants with state-aware data.
     * Prevents infinite recursion by skipping the original invoker.
     * 
     * @param {Data} data - Combined data including updated state values
     * @param {TagHandler} invoker - The handler that initiated the state change (will be skipped)
     */
    stateRefresh(data, invoker) {
        if (this === invoker) {
            // Skip the invoker to prevent infinite recursion
            return;
        }
        this.refresh(data); 
        for (var handler of this.descendantHandlers) {
            handler.stateRefresh(data, invoker);
        }
    }


    /**
     * @protected
     */
    publishBindEvent() {
        this.onBind();
        for (var handler of this.descendantHandlers) {
            handler.publishBindEvent();
        }
    }

    /**
     * @protected
     */
    onBind() {

    }

    /**
     * Refreshes descendant handlers.
     * 
     * @param {Data} data
     * @returns {Promise}
     */
    refreshDescendantHandlers(data) {
        var promises = [];
        for (var handler of this.descendantHandlers) {
            promises.push(handler.refresh(data));
        }
        return Promise.all(promises);
    }

    refreshFormData(data) {
        for (var handler of this.descendantHandlers) {
            handler.refreshFormData(data);
        }
    }

    clearChildren() {
        for (var node of this.nodeListToArray(this.tag.childNodes)) {
            if (node.getAttribute && node.getAttribute('ignore')) {
                continue;
            }
            if (node.parentNode) {
                node.parentNode.removeChild(node);
            }
        }
        for (var handler of this.descendantHandlers) {
           handler.parentHandler = null;
        }
        this.descendantHandlers = [];
    }

    appendAttribute(attrName, appendValue) {
        // TODO Decide whether this should become a supported form-field feature, likely on blur or input instead.
        if (this.tag.getAttribute('xis:submit-onkeyup')) {
            var attr = '';
            if (element.getAttribute(attrName)) {
                attr += element.getAttribute(attrName);
                if (!trim(attr).endsWith(";")) {
                    attr += ';'
                }
            }
            attr += appendValue;
            this.tag.setAttribute('onkeyup', attr);
        }
    }

    createExpression(src) {
        return new TextContentParser(src, this).parse();
    }

    variableTextContentFromAttribute(attrName) {
        var attr = this.tag.getAttribute(attrName);
        if (attr) {
            return new TextContentParser(attr, this).parse();
        }
    }

    expressionFromAttribute(attrName) {
        var attr = this.tag.getAttribute(attrName);
        if (attr) {
            return this.expressionParser.parse(attr);
        }
    }

    findParentFrontletContainer() {
        var e = this.tag;
        while (e) {
            if (e.localName == 'xis:frontlet-container') {
                return e;
            }
            e = e.parentNode;
        }
    }

    getParentFormHandler()  {
        var handler = this.findParentFormHandler();
        if (handler) {
            return handler;
        }
        throw new Error('no parent form-handler for ' + this.tag 
            +". May be you forgot to add xis:binding to the form?");
    }

    findParentFormHandler() {
        var handler = this;
        while (handler) {
            if (handler.type == 'form-handler') {
                return handler;
            }
            handler = handler.parentHandler;
        }
    }

    findParentFrontletContainerHandler() {
        var handler = this;
        while (handler) {
            if (handler.type == 'frontlet-container-handler') {
                return handler;
            }
            handler = handler.parentHandler;
        }
        return null;
    }

    isFrameworkElement(node) {
        return isElement(node) && node.localName.startsWith('xis:');
    }


    isVisible(node) {
        return node.parentNode != null;
    }

    nodeListToArray(nodeList) {
        var arr = [];
        for (var i = 0; i < nodeList.length; i++) {
            arr.push(nodeList.item(i));
        }
        return arr;
    }

    getAttribute(name) {
        return this.tag.getAttribute(name);
    }

    hasAttribute(name) {
        return this.tag.hasAttribute(name);
    }

    doSplit(string, separatorChar) {
        var rv = [];
        var buffer = '';
        for (var i = 0; i < string.length; i++) {
            var c = string.charAt(i);
            if (c === separatorChar) {
                rv.push(buffer);
                buffer = '';
            } else {
                buffer += c;
            }
        }
        rv.push(buffer);
        return rv;
    }
}

